  2→import { sanitizeProjectPhaseReferences } from '@/domain/phaseAssignments';
  3→import { createFloor } from '@/domain/models';
  4→import { createAnnotationSettings } from '@/domain/models';
  5→import { CURRENT_PROJECT_VERSION, isSupportedProjectFileVersion } from '@/domain/projectVersion';
  6→import { normalizePhases } from '@/domain/phaseModels';
  7→import { createRoofSystem, syncRoofSystemAttachment } from '@/domain/roofModels';
  8→import {
  9→  createTrussInstance,
 10→  createTrussSystem,
 11→  syncProjectTrussSystems,
 12→  TRUSS_SUPPORT_MODES,
 13→} from '@/domain/trussModels';
 14→import { getDefaultActiveFloorId, getFloorElevation, getFloorLevelIndex, getFloorToFloorHeight, getFloorTopElevation, sortFloors } from '@/domain/floorModels';
 15→import { createSheetRevision } from '@/domain/sheetModels';
 16→
 17→export function deserializeProject(json) {
 18→  if (!json || !json.version || !json.data) {
 19→    throw new Error('Invalid project data');
 20→  }
 21→  if (!isSupportedProjectFileVersion(json.version)) {
 22→    throw new Error(`Unsupported project version: ${json.version}`);
 23→  }
 24→
 25→  let project = json.data;
 26→
 27→  // Basic validation
 28→  if (!project.id || !project.name || !Array.isArray(project.floors)) {
 29→    throw new Error('Invalid project structure');
 30→  }
 31→
 32→  if (!Array.isArray(project.sheets)) {
 33→    project.sheets = [];
 34→  }
 35→  if (project.roofSystem === undefined) {
 36→    project.roofSystem = null;
 37→  }
 38→  if (!Array.isArray(project.trussSystems)) {
 39→    project.trussSystems = [];
 40→  }
 41→  if (project.address === undefined) project.address = '';
 42→  project.documentDefaults = {
 43→    drawnBy: project.documentDefaults?.drawnBy ?? '',
 44→    checkedBy: project.documentDefaults?.checkedBy ?? '',
 45→  };
 46→  project.version = Math.max(CURRENT_PROJECT_VERSION, Number(project.version || 0));
 47→
 48→  if (project.floors.length === 0) {
 49→    project.floors = [createFloor('Ground Floor', 0)];
 50→  }
 51→
 52→  for (const floor of project.floors) {
 53→    if (!floor.id || !Array.isArray(floor.walls)) {
 54→      throw new Error('Invalid floor structure');
 55→    }
 56→  }
 57→
 58→  // Backfill missing room fields for old saves
 59→  project.floors.forEach((floor, index) => {
 60→    if (!floor.name) floor.name = index === 0 ? 'Ground Floor' : `Floor ${index}`;
 61→    if (floor.levelIndex === undefined) {
 62→      floor.levelIndex = floor.level ?? index;
 63→    }
 64→    if (floor.floorToFloorHeight === undefined) {
 65→      floor.floorToFloorHeight = WALL_HEIGHT;
 66→    }
 67→    if (floor.elevation === undefined) {
 68→      floor.elevation = floor.level ?? (floor.levelIndex * floor.floorToFloorHeight);
 69→    }
 70→    delete floor.level;
 71→
 72→    if (!floor.rooms) floor.rooms = [];
 73→    for (const room of floor.rooms) {
 74→      if (!room.points) room.points = [];
 75→      if (room.area === undefined) room.area = 0;
 76→    }
 77→  });
 78→
 79→  // Backfill door/window type fields for old saves
 80→  for (const floor of project.floors) {
 81→    if (!floor.doors) floor.doors = [];
 82→    for (const door of floor.doors) {
 83→      if (!door.type) door.type = 'swing';
 84→      if (door.height === undefined) door.height = DOOR_HEIGHT;
 85→      if (door.sillHeight === undefined) door.sillHeight = DOOR_SILL_HEIGHT;
 86→    }
 87→    if (!floor.windows) floor.windows = [];
