 89→      if (!win.type) win.type = 'standard';
 90→      if (!win.openDirection) win.openDirection = 'left';
 91→      if (win.height === undefined) win.height = WINDOW_HEIGHT;
 92→      if (win.sillHeight === undefined) win.sillHeight = WINDOW_SILL_HEIGHT;
 93→    }
 94→    if (!floor.columns) floor.columns = [];
 95→    if (!floor.fixtures) floor.fixtures = [];
 96→    if (!floor.beams) floor.beams = [];
 97→    if (!floor.stairs) floor.stairs = [];
 98→    if (!floor.landings) floor.landings = [];
 99→    if (!floor.annotations) floor.annotations = [];
100→    floor.annotationSettings = createAnnotationSettings(floor.annotationSettings || {});
101→    // Migrate single slab → slabs array
102→    if (floor.slab !== undefined) {
103→      floor.slabs = floor.slab ? [floor.slab] : [];
104→      delete floor.slab;
105→    }
106→    if (!Array.isArray(floor.slabs)) floor.slabs = [];
107→    // Migrate single sectionCut → sectionCuts array
108→    if (floor.sectionCut !== undefined) {
109→      floor.sectionCuts = floor.sectionCut ? [floor.sectionCut] : [];
110→      delete floor.sectionCut;
111→    }
112→    if (!Array.isArray(floor.sectionCuts)) floor.sectionCuts = [];
113→    for (const wall of floor.walls) {
114→      if (wall.height === undefined) wall.height = WALL_HEIGHT;
115→      if (wall.startAttachment === undefined) wall.startAttachment = null;
116→      if (wall.endAttachment === undefined) wall.endAttachment = null;
117→    }
118→    for (const column of floor.columns) {
119→      if (column.showLabel === undefined) {
120→        column.showLabel = Boolean(column.name);
121→      }
122→    }
123→    for (const fixture of floor.fixtures) {
124→      if (!fixture.fixtureType) fixture.fixtureType = 'kitchenTop';
125→      if (fixture.x === undefined) fixture.x = 0;
126→      if (fixture.y === undefined) fixture.y = 0;
127→      if (fixture.width === undefined) fixture.width = 600;
128→      if (fixture.depth === undefined) fixture.depth = 400;
129→      if (fixture.rotation === undefined) fixture.rotation = 0;
130→      if (fixture.name === undefined) fixture.name = '';
131→    }
132→    for (const beam of floor.beams) {
133→      if (beam.floorLevel === undefined) beam.floorLevel = getFloorElevation(floor, index);
134→    }
135→    for (const stair of floor.stairs) {
136→      if (!stair.startPoint) stair.startPoint = { x: 0, y: 0 };
137→      if (stair.width === undefined) stair.width = STAIR_WIDTH;
138→      if (stair.numberOfRisers === undefined) stair.numberOfRisers = STAIR_RISERS;
139→      if (stair.riserHeight === undefined) stair.riserHeight = STAIR_RISER_HEIGHT;
