147→      }
148→      if (stair.floorRelation === undefined) {
149→        stair.floorRelation = { fromFloorId: floor.id, toFloorId: floor.id };
150→      } else {
151→        if (stair.floorRelation.fromFloorId === undefined) stair.floorRelation.fromFloorId = floor.id;
152→        if (stair.floorRelation.toFloorId === undefined) stair.floorRelation.toFloorId = floor.id;
153→      }
154→      if (stair.startLandingAttachment === undefined) stair.startLandingAttachment = null;
155→      if (stair.endLandingAttachment === undefined) stair.endLandingAttachment = null;
156→      if (stair.roofAccess === undefined) stair.roofAccess = null;
157→    }
158→    for (const landing of floor.landings) {
159→      if (!landing.position) landing.position = { x: 0, y: 0 };
160→      if (landing.width === undefined) landing.width = 1000;
161→      if (landing.depth === undefined) landing.depth = 1000;
162→      if (landing.thickness === undefined) landing.thickness = 200;
163→      if (landing.elevation === undefined) landing.elevation = 0;
164→      if (landing.rotation === undefined) landing.rotation = 0;
165→    }
166→    for (const annotation of floor.annotations) {
167→      if (!annotation.id) {
168→        annotation.id = `anno_${floor.id}_${Math.random().toString(36).slice(2, 8)}`;
169→      }
170→      if (!annotation.type) annotation.type = 'dimension';
171→      if (!annotation.mode) annotation.mode = 'aligned';
172→      if (!annotation.startPoint) annotation.startPoint = { x: 0, y: 0 };
173→      if (!annotation.endPoint) annotation.endPoint = { x: 0, y: 0 };
174→      if (annotation.offset === undefined) annotation.offset = 300;
175→      if (annotation.textOverride === undefined) annotation.textOverride = '';
176→    }
177→    for (const slab of floor.slabs) {
178→      if (!slab.floorId) slab.floorId = floor.id;
179→      if (!slab.boundaryPoints) slab.boundaryPoints = [];
180→      if (slab.thickness === undefined) slab.thickness = SLAB_THICKNESS;
181→      if (slab.elevation === undefined) slab.elevation = SLAB_ELEVATION;
182→      if (slab.name === undefined) slab.name = '';
183→      if (slab.type === undefined) slab.type = '';
184→    }
185→    for (const sc of floor.sectionCuts) {
186→      if (!sc.id) {
187→        sc.id = `section_${floor.id}_${Math.random().toString(36).slice(2, 8)}`;
188→      }
189→      if (!sc.startPoint) sc.startPoint = { x: 0, y: 0 };
190→      if (!sc.endPoint) sc.endPoint = { x: 1000, y: 0 };
191→      if (sc.depth === undefined) sc.depth = 2000;
192→      if (sc.label === undefined) sc.label = 'Section A-A';
193→      if (sc.direction === undefined) sc.direction = 1;
194→    }
195→  }
196→
197→  project.floors = sortFloors(project.floors).map((floor, index) => ({
198→    ...floor,
199→    levelIndex: getFloorLevelIndex(floor, index),
200→    elevation: getFloorElevation(floor, index),
201→    floorToFloorHeight: getFloorToFloorHeight(floor),
202→  }));
203→
204→  project.trussSystems = (project.trussSystems || []).map((trussSystem) => {
205→    const floor = project.floors.find((entry) => entry.id === trussSystem.floorId)
206→      || project.floors.find((entry) => entry.id === getDefaultActiveFloorId(project))
207→      || project.floors[0]
208→      || null;
209→    const floorId = floor?.id || null;
210→
211→    return {
212→      ...createTrussSystem(trussSystem.name || 'Truss System'),
213→      ...trussSystem,
214→      id: trussSystem?.id || `truss_system_${Math.random().toString(36).slice(2, 8)}`,
215→      floorId,
216→      baseElevation: trussSystem?.baseElevation ?? (floor ? getFloorTopElevation(floor) : 0),
217→      trussInstances: (trussSystem.trussInstances || []).map((trussInstance) => ({
218→        ...createTrussInstance({ floorId }),
219→        ...trussInstance,
220→        id: trussInstance?.id || `truss_instance_${Math.random().toString(36).slice(2, 8)}`,
221→        floorId: trussInstance?.floorId || floorId,
222→        startPoint: trussInstance?.startPoint ? { x: trussInstance.startPoint.x, y: trussInstance.startPoint.y } : { x: -6000, y: 0 },
223→        endPoint: trussInstance?.endPoint ? { x: trussInstance.endPoint.x, y: trussInstance.endPoint.y } : { x: 6000, y: 0 },
224→        bearingOffsets: {
225→          start: Number.isFinite(trussInstance?.bearingOffsets?.start) ? trussInstance.bearingOffsets.start : 0,
226→          end: Number.isFinite(trussInstance?.bearingOffsets?.end) ? trussInstance.bearingOffsets.end : 0,
227→        },
228→        overhangs: {
229→          start: Number.isFinite(trussInstance?.overhangs?.start) ? trussInstance.overhangs.start : 300,
230→          end: Number.isFinite(trussInstance?.overhangs?.end) ? trussInstance.overhangs.end : 300,
231→        },
232→        supportMode: trussInstance?.supportMode === TRUSS_SUPPORT_MODES.BEAM_PAIR
233→          ? TRUSS_SUPPORT_MODES.BEAM_PAIR
234→          : null,
235→        supportBeamIds: {
236→          start: typeof trussInstance?.supportBeamIds?.start === 'string' ? trussInstance.supportBeamIds.start : null,
237→          end: typeof trussInstance?.supportBeamIds?.end === 'string' ? trussInstance.supportBeamIds.end : null,
238→        },
239→        roofAttachmentId: trussInstance?.roofAttachmentId || null,
240→      })),
241→    };
242→  });
243→  project = syncProjectTrussSystems(project);
244→
245→  if (project.roofSystem) {
246→    const roofSystem = {
247→      ...createRoofSystem(project.roofSystem.name || 'Roof'),
248→      ...project.roofSystem,
249→      trussAttachmentId: project.roofSystem.trussAttachmentId || null,
250→      boundaryPolygon: (project.roofSystem.boundaryPolygon || []).map((point) => ({
251→        x: point.x,
252→        y: point.y,
253→      })),
254→      parapets: (project.roofSystem.parapets || []).map((parapet) => ({
255→        ...parapet,
256→        startPoint: parapet.startPoint ? { x: parapet.startPoint.x, y: parapet.startPoint.y } : { x: 0, y: 0 },
257→        endPoint: parapet.endPoint ? { x: parapet.endPoint.x, y: parapet.endPoint.y } : { x: 1000, y: 0 },
258→        attachment: parapet.attachment
259→          ? {
260→              type: parapet.attachment.type ?? 'roof_edge',
261→              edgeIndex: Number.isFinite(parapet.attachment.edgeIndex) ? parapet.attachment.edgeIndex : 0,
262→              startOffset: Number.isFinite(parapet.attachment.startOffset) ? parapet.attachment.startOffset : 0,
263→              endOffset: Number.isFinite(parapet.attachment.endOffset) ? parapet.attachment.endOffset : 0,
264→            }
265→          : null,
266→      })),
267→      drains: (project.roofSystem.drains || []).map((drain) => ({
268→        ...drain,
269→        position: drain.position ? { x: drain.position.x, y: drain.position.y } : { x: 0, y: 0 },
270→      })),
271→      roofOpenings: (project.roofSystem.roofOpenings || []).map((opening) => ({
272→        ...opening,
273→        boundaryPoints: (opening.boundaryPoints || []).map((point) => ({
274→          x: point.x,
275→          y: point.y,
276→        })),
277→      })),
278→      roofPlanes: (project.roofSystem.roofPlanes || []).map((plane) => ({
279→        ...plane,
280→        boundaryPoints: (plane.boundaryPoints || []).map((point) => ({
281→          x: point.x,
282→          y: point.y,
283→        })),
284→      })),
285→      roofEdges: (project.roofSystem.roofEdges || []).map((edge) => ({
286→        ...edge,
287→        startPoint: edge.startPoint ? { x: edge.startPoint.x, y: edge.startPoint.y } : { x: 0, y: 0 },
288→        endPoint: edge.endPoint ? { x: edge.endPoint.x, y: edge.endPoint.y } : { x: 1000, y: 0 },
289→        planeIds: [...new Set(edge.planeIds || [])],
290→      })),
291→      ridges: (project.roofSystem.ridges || []).map((ridge) => ({
292→        ...ridge,
293→        startPoint: ridge.startPoint ? { x: ridge.startPoint.x, y: ridge.startPoint.y } : { x: 0, y: 0 },
294→        endPoint: ridge.endPoint ? { x: ridge.endPoint.x, y: ridge.endPoint.y } : { x: 1000, y: 0 },
295→        planeIds: [...new Set(ridge.planeIds || [])],
296→      })),
297→      valleys: (project.roofSystem.valleys || []).map((valley) => ({
298→        ...valley,
299→        startPoint: valley.startPoint ? { x: valley.startPoint.x, y: valley.startPoint.y } : { x: 0, y: 0 },
300→        endPoint: valley.endPoint ? { x: valley.endPoint.x, y: valley.endPoint.y } : { x: 1000, y: 0 },
301→        planeIds: [...new Set(valley.planeIds || [])],
302→      })),
303→      hips: (project.roofSystem.hips || []).map((hip) => ({
304→        ...hip,
305→        startPoint: hip.startPoint ? { x: hip.startPoint.x, y: hip.startPoint.y } : { x: 0, y: 0 },
306→        endPoint: hip.endPoint ? { x: hip.endPoint.x, y: hip.endPoint.y } : { x: 1000, y: 0 },
307→        planeIds: [...new Set(hip.planeIds || [])],
308→      })),
309→    };
310→
311→    project.roofSystem = syncRoofSystemAttachment(project, roofSystem);
312→  }
313→
314→  for (const sheet of project.sheets) {
315→    if (!sheet.id) {
316→      sheet.id = `sheet_${Math.random().toString(36).slice(2, 8)}`;
317→    }
318→    if (sheet.title === undefined) sheet.title = '';
319→    if (sheet.paperSize === undefined) sheet.paperSize = 'A3_LANDSCAPE';
320→    if (sheet.number === undefined) sheet.number = '';
321→    if (sheet.issueDate === undefined) sheet.issueDate = '';
322→    if (sheet.scaleLabel === undefined) sheet.scaleLabel = '1:100';
323→    if (sheet.scaleMode === undefined) sheet.scaleMode = 'custom';
324→    if (sheet.layoutTemplate === undefined) sheet.layoutTemplate = 'auto';
325→    if (sheet.drawingName === undefined) sheet.drawingName = sheet.title || 'Drawing';
326→    if (sheet.projectNameOverride === undefined) sheet.projectNameOverride = '';
327→    sheet.titleBlock = {
328→      projectTitleOverride: sheet.titleBlock?.projectTitleOverride ?? '',
329→      projectAddressOverride: sheet.titleBlock?.projectAddressOverride ?? '',
330→      drawnBy: sheet.titleBlock?.drawnBy ?? '',
331→      checkedBy: sheet.titleBlock?.checkedBy ?? '',
332→    };
333→    if (!Array.isArray(sheet.revisions)) sheet.revisions = [];
334→    sheet.revisions = sheet.revisions.map((revision) => ({
335→      ...createSheetRevision(),
336→      ...revision,
337→      id: revision?.id || `revision_${sheet.id}_${Math.random().toString(36).slice(2, 8)}`,
338→    }));
339→    if (!Array.isArray(sheet.viewports)) sheet.viewports = [];
340→
341→    for (const viewport of sheet.viewports) {
342→      if (!viewport.id) {
343→        viewport.id = `viewport_${sheet.id}_${Math.random().toString(36).slice(2, 8)}`;
344→      }
345→      if (viewport.sourceView === undefined) viewport.sourceView = 'plan';
346→      if (viewport.sourceFloorId === undefined) viewport.sourceFloorId = getDefaultActiveFloorId(project);
347→      if (viewport.sourceRefId === undefined) viewport.sourceRefId = null;
348→      if (viewport.x === undefined) viewport.x = 20;
349→      if (viewport.y === undefined) viewport.y = 20;
350→      if (viewport.width === undefined) viewport.width = 160;
351→      if (viewport.height === undefined) viewport.height = 100;
352→      if (viewport.scale === undefined) viewport.scale = 100;
353→      if (viewport.title === undefined) viewport.title = '';
354→      if (viewport.rotation === undefined) viewport.rotation = 0;
355→      if (viewport.role === undefined) viewport.role = viewport.sourceView === '3d_preview'
356→        ? 'supplemental'
357→        : ((viewport.sourceView === 'plan' || viewport.sourceView === 'roof_plan' || viewport.sourceView === 'roof_drainage' || viewport.sourceView === 'truss_plan')
358→          ? 'primary'
359→          : (viewport.sourceView === 'truss_detail' ? 'detail' : 'secondary'));
360→      if (viewport.captionPosition === undefined) viewport.captionPosition = 'below';
361→      if (viewport.referenceNote === undefined) viewport.referenceNote = '';
362→      if (viewport.lockAutoLayout === undefined) viewport.lockAutoLayout = false;
363→      if (viewport.phaseId === undefined) viewport.phaseId = null;
364→      if (viewport.phaseViewMode === undefined) viewport.phaseViewMode = 'all';
365→    }
366→  }
367→
368→  project.phases = normalizePhases(project.phases || []);
369→  const validPhaseIds = new Set(project.phases.map((phase) => phase.id));
370→
371→  return {
372→    project: sanitizeProjectPhaseReferences(project, validPhaseIds),
373→    savedAt: json.savedAt,
374→  };
375→}
